mapper.select:
		
		SELECT * FROM (
			SELECT ROWNUM AS RNUM, list.* FROM (
				SELECT * FROM bnc_project
				WHERE (proj_req_biznum = #{companyData.cmpy_biznum} OR proj_acp_biznum = #{companyData.cmpy_biznum})
		
			
				
					AND ${pageData.searchType} like '%'||#{pageData.searchKeyword}||'%'
	         	
			
				order by proj_number DESC
		
			) list
		)
		
      
		
		WHERE RNUM > #{pageData.startRowNumber} AND RNUM <= #{pageData.endRowNumber}

		
		SELECT * FROM (
			SELECT ROWNUM AS RNUM, list.* FROM (
				SELECT * FROM bnc_project project 
		
			
				
					WHERE project.${searchType} like '%'||#{searchKeyword}||'%'
	         	
			
				order by proj_number DESC
		
			) list
		)
		
      
		
		WHERE RNUM > #{startRowNumber} AND RNUM <= #{endRowNumber}

